{
  "name": "Delaware LIHEAP",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must be at or below 60% of Delaware State Median Income (SMI), after federal and local taxes. Recent 2025 guidelines: 1 person $3,278/month ($39,336/year), 2 people $4,287/month ($51,444/year), 3 people $5,296/month ($63,552/year), 4 people $6,304/month ($75,648/year), 5 people $7,313/month ($87,756/year), 6 people $8,322/month ($99,864/year). Older data (2021) used 200% FPL annually: 1 person $25,536, 2 $34,488, 3 $43,440, 4 $52,416[1][2][4].",
    "asset_limits": "No asset limit applies[1].",
    "other_requirements": ["Household includes all at the address sharing utility bills (e.g., roommates count)[1]", "Eligible heating fuels: electricity, natural gas, oil, kerosene, propane, coal, wood[4]", "Homeowners and renters qualify[2][4]", "Priority for elderly (60+), disabled, families with young children[5]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Regular heating: $100 min to $2,561 max; cooling: $1 min to $1,000 max; crisis: up to $10,000 max. Paid as one-time grant to utility or household. Average ~$553/year. Includes winter heating (Oct-Mar), year-round crisis aid, summer cooling flat benefit. Weatherization separate (insulation, repairs)[1][4][6].",
    "varies_by": "household_size|priority_tier|fuel_type"
  },
  "application": {
    "methods": ["Online: dhss.delaware.gov/dhss/dss/liheap.html or Catholic Charities (specific link via site)[4]", "Phone: (302) 255-9875[4]", "Local agencies via Division of State Service Centers (DSSC)[4]", "In-person/mail through contracted local providers like Catholic Charities[4]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Funds vary by demand and enrollment timing; no guaranteed availability[6]",
    "forms": ["LIHEAP application via local provider or online portal; Delaware Nation form example for reference[5]"],
    "documents": ["Proof of income (after taxes), household size, utility bills/shut-off notices for crisis, fuel type[1][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide; administered via local agencies",
    "regional_variations": "Contracted to local providers (e.g., Catholic Charities); potential differences in processing by agency, but uniform eligibility[4]",
    "offices_or_providers": ["Catholic Charities Diocese of Wilmington: Phone (302) 255-9875, Fax (302) 255-4463[4]", "Other DSSC-contracted local agencies"]
  },
  "official_source": "https://www.dhss.delaware.gov/dhss/dss/liheap.html",
  "gotchas": ["Income is gross monthly before taxes for household sharing utilities (roommates count)[1]", "Supplemental only, not full heating costs[4]", "Priority groups (elderly 60+, disabled) get preference but no strict age cutoff[5]", "Older income data (e.g., 2021) outdated; verify current SMI/200% FPL[1][2]", "Crisis requires proof like shut-off notice or low fuel (≤10%)[4]", "Funds not guaranteed; apply early in season[6]"],
  "data_shape_notes": "Income at 60% SMI or 200% FPL (updates yearly); benefits scale by income/size/fuel/season; priority tiers for vulnerable; statewide but local agency delivery; no assets test"
}

{
  "name": "Delaware Senior Medicare Patrol (SMP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, their families, and caregivers[1][3][4]",
    "asset_limits": "No asset limits or tests apply[1][3]",
    "other_requirements": ["Must be a Medicare beneficiary (age 65+, younger with disabilities or ESRD), family member, or caregiver seeking help with Medicare fraud prevention, detection, reporting, errors, abuse, or health insurance counseling[1][3][4]"]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free one-on-one counseling on Medicare fraud, errors, abuse; community outreach and education presentations at events, health fairs, senior centers, libraries; dissemination of consumer education materials; advocacy to resolve billing disputes; referrals to state/federal agencies for suspected fraud investigations; SHIP services including free local health insurance counseling, outreach, and training on Medicare options[1][2][4][5][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (302) 255-9642 (primary contact Barbara Jackson) or (800) 223-9074 (national volunteer line, also for services)[4]", "Website: https://smp.dhss.delaware.gov/[6]", "In-person: Events at libraries, health fairs, senior centers statewide (e.g., Frankford Public Library)[7][8]"],
    "processing_time": "Immediate for counseling and education; no formal application processing as services are provided on-demand via phone, events, or contact[1][2][4]",
    "waitlist": null,
    "forms": ["No specific forms required; contact for complaints or education[2]"],
    "documents": ["Medicare card, billing statements, or details of suspected fraud/errors/abuse for counseling; none required for general education/outreach[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Delaware Medicare beneficiaries statewide[4][5][7]",
    "regional_variations": "No differences by county or region; uniform state program with events at local sites like libraries and senior centers[7][8]",
    "offices_or_providers": ["Delaware Senior Medicare Patrol, contact Barbara Jackson at (302) 255-9642 or barbara.jackson@delaware.gov[4]"]
  },
  "official_source": "https://smp.dhss.delaware.gov/[6]",
  "gotchas": ["Not a financial assistance or healthcare benefits program—focuses solely on education, counseling, and fraud reporting, not direct aid or enrollment in Medicare benefits[1][2][3]", "Often paired with SHIP but SMP specifically targets fraud prevention/detection[1][3]", "Volunteer-based with no cost to users, but funded by federal grants which may face cuts[7]", "Contact for services, not formal 'application' as it's not an entitlement program[4]"],
  "data_shape_notes": "no income/asset/age test beyond Medicare eligibility; service-based not financial; volunteer-driven outreach statewide via events/phone; often bundled with SHIP counseling[1][2][3][4]"
}

