    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-223-9074[2]", "Website: www.dhss.delaware.gov/dhss[2]", "In-person or facility referral via regional offices (e.g., Kent/Sussex via Delaware ADRC)[6]"],
    "processing_time": "Not specified; complaint investigations begin upon contact, with periodic site visits[4]",
    "waitlist": null,
    "forms": ["No specific application form required; contact directly to file complaint or request assistance[2][5]"],
    "documents": ["No documents needed to initiate; provide details of complaint/concern (e.g., resident name, facility, issue description)[4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to licensed long-term care facilities statewide[4][5][6]",
    "regional_variations": "Regional volunteer coordination (e.g., Kent/Sussex specific contacts via ADRC); main office at 1901 N DuPont Hwy, New Castle, DE 19720; no noted differences in services, wait times, or eligibility[1][2][6]",
    "offices_or_providers": ["Main Administration: 1901 N DuPont Hwy, New Castle, DE 19720[1][2]", "Kent/Sussex coordination via Delaware ADRC[6]"]
  },
  "official_source": "https://dhss.delaware.gov/dhss (primary state DHSS site)[2]",
  "gotchas": ["Not a direct service provider (no healthcare/financial aid); focuses on advocacy/complaints only[4][5]", "Abuse/neglect complaints referred to Division of Long Term Care Residents Protection, not handled directly[5]", "Volunteers cannot serve if family works/resides in assigned facility or conflict of interest exists[2]", "Families can contact on behalf of residents; no personal eligibility barriers[2][6]"],
